321	        GameState gs_after_tilt = current_gs_after_placement;
322	        gs_after_tilt.apply_tilt(i);
323	
324	        double eval = eval_lookahead(gs_after_tilt, turn_T, config.max_depth, config);
325	
326	        if (eval > best_overall_eval) {
327	            best_overall_eval = eval;
328	            best_dir_idx = i;
329	        }
330	    }
331	    return DIR_CHARS[best_dir_idx];
332	}
