335	double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed, int depth_remaining, const LookaheadConfig& config) {
336	    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
337	        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
338	        return state_after_tilt.evaluate();
339	    }
340	
341	    int num_empty = state_after_tilt.count_empty_cells();
342	    if (num_empty == 0) {
343	        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
344	        return state_after_tilt.evaluate();
345	    }
346	
347	    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
348	    int sample_count_param_idx = config.max_depth - depth_remaining;
349	    int sample_count_this_depth = config.samples[sample_count_param_idx];
350	    int actual_num_samples = std::min(sample_count_this_depth, num_empty);
351	
352	    if (actual_num_samples == 0) {
353	        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
354	        return state_after_tilt.evaluate();
355	    }
356	
357	    double sum_over_sampled_placements = 0.0;
358	    for (int s = 0; s < actual_num_samples; ++s) {
359	        int p_val;
360	        if (actual_num_samples == num_empty) {
361	            p_val = s + 1;
362	        } else {
363	            p_val = rng.uniform_int(1, num_empty);
364	        }
365	
366	        GameState S_after_placement = state_after_tilt;
367	        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val);
368	        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
369	        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;
370	
371	        double max_eval = std::numeric_limits<double>::lowest();
372	        for (int dir_idx = 0; dir_idx < NUM_DIRECTIONS; ++dir_idx) {
373	            GameState S_after_tilt = S_after_placement;
374	            S_after_tilt.apply_tilt(dir_idx);
375	            double val = eval_lookahead(S_after_tilt, S_after_placement.turn_num_1_indexed, depth_remaining - 1, config);
376	            if (val > max_eval) {
377	                max_eval = val;
378	            }
379	        }
380	        sum_over_sampled_placements += max_eval;
381	    }
382	
383	    return sum_over_sampled_placements / actual_num_samples;
384	}
