    std::array<int, 4> dir_order = {0, 1, 2, 3};
    std::sort(dir_order.begin(), dir_order.end(), [&](int a, int b) {
        return scores_r1[a] > scores_r1[b];
    });

    // Round 2: deeper evaluation of top 2
    double best_eval = std::numeric_limits<double>::lowest();
    int best_dir = dir_order[0];

