// Time-budgeted iterative deepening: run eval_lookahead repeatedly per direction
// and average the results. Each call uses independent random samples internally.
char decide_tilt_direction_logic(const GameState& current_gs_after_placement) {
    int turn_T = current_gs_after_placement.turn_num_1_indexed;

    double now = elapsed_ms();
    double total_deadline_ms = 1850.0;
    double remaining = total_deadline_ms - now;
    int turns_left = NUM_TURNS - turn_T + 1;
    double time_budget_ms = remaining / turns_left * 1.2;
