        config.samples[0] = 8;
        config.samples[1] = 4;
        config.samples[2] = 3;
        config.use_fast_at_leaf = true;
    } else {
        config.max_depth = 2;
        config.samples[0] = 18;
        config.samples[1] = 5;
        config.samples[2] = 0;
        config.use_fast_at_leaf = false;
    }

