    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
        accum_eval[i] = eval_lookahead(tilted_states[i], turn_T, config.max_depth, config);
        accum_count[i] = 1;
    }

    // Iterative refinement until time budget exhausted
    while (elapsed_ms() < deadline) {
        // Find the direction with fewest samples among the top-2
        int best_i = 0, second_i = -1;
        for (int i = 1; i < NUM_DIRECTIONS; ++i) {
            if (accum_eval[i] / accum_count[i] > accum_eval[best_i] / accum_count[best_i]) {
                second_i = best_i;
                best_i = i;
            } else if (second_i == -1 || accum_eval[i] / accum_count[i] > accum_eval[second_i] / accum_count[second_i]) {
                second_i = i;
            }
